import{_ as t,o,c as s,ae as n}from"./chunks/framework.BIONGpTb.js";const g=JSON.parse('{"title":"What is Eclipse Docks","description":"","frontmatter":{},"headers":[],"relativePath":"intro.md","filePath":"intro.md"}'),a={name:"intro.md"};function i(r,e,c,d,l,p){return o(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="what-is-eclipse-docks" tabindex="-1">What is Eclipse Docks <a class="header-anchor" href="#what-is-eclipse-docks" aria-label="Permalink to &quot;What is Eclipse Docks&quot;">​</a></h1><p>Eclipse Docks is a <strong>modular web framework</strong> for building IDE-like applications. It provides:</p><ul><li><strong>App layer</strong> — You define an app by its extensions and optional layout; the app root is the chosen layout&#39;s component. Layouts (e.g. IDE, dashboard) are registered via contributions; users switch via the toolbar. The framework handles registration, lifecycle, and rendering.</li><li><strong>Extension system</strong> — Features (editor, terminal, AI, settings, etc.) are packaged as extensions. Each extension registers with the core and can contribute UI and commands.</li><li><strong>Contributions</strong> — Declarative UI: tabs in sidebars, buttons on toolbars, HTML blocks. Contributions are bound to targets (e.g. main sidebar, bottom panel).</li><li><strong>Commands</strong> — Named actions with handlers. Toolbars and menus reference commands; the command palette and AI can execute them.</li><li><strong>Core services</strong> — Workspace, settings, dialogs, tasks, events, and dependency injection.</li></ul><p>You can build a <strong>downstream app</strong> by defining an <code>AppDefinition</code> and choosing which extensions to enable, or author <strong>new extensions</strong> that register with <code>extensionRegistry</code>, <code>contributionRegistry</code>, and <code>commandRegistry</code>.</p><p>See <a href="/docs/concepts/architecture.html">Architecture</a> and the <a href="/docs/guide/getting-started.html">Guide</a> for details.</p>',5)])])}const m=t(a,[["render",i]]);export{g as __pageData,m as default};
